<script name="App" setup>
import { useStore, useWebUIStore } from '@/stores'
import { ElMessage } from 'element-plus'
import { reactive, onMounted, ref } from 'vue'
import * as ps from '@/utils/ps'
import Txt2Img from './components/txt2img.vue'
import Inpaint from './components/inpaint.vue'
import Outpaint from './components/outpaint.vue'

const webuiStore = useWebUIStore()
const store = useStore()
const form = reactive({
  form: {
    type: ""
  }
})


// const value = ref('sd Core')
const options = [
  {
    value: 'sd3',
    label: 'Stable Diffusion 3.5',
  },
  {
    value: 'core',
    label: 'Stable Diffusion Core',
  },
  {
    value: 'ultra',
    label: 'Stable Diffusion Ultra',
  },
]



const handleCutout = async () => {
  try {
    webuiStore.loading = true
    await webuiStore.cutoutHandle(form)
  } catch (err) {
    console.log('error', err)
    ElMessage.error(err.message)
  }
  webuiStore.loading = false
  console.log('submit!')
}

const handleErase = async () => {
  let mask = ps.getSelectArea()
  if (!mask) {
    ElMessage.error('Select the area you want to erase using a selection tool.')
    return
  }

  try {
    webuiStore.loading = false
    await webuiStore.eraseHandle(form)
  } catch (err) {
    console.log('error', err)
    ElMessage.error(err.message)
  }
  webuiStore.loading = false
  console.log('submit!')
}


const handleButtonClick = (t) => {
  form.type = t
  if ("cutout" === t) {
    handleCutout()
    return
  }
  if ("erase" === t) {
    handleErase()
    return
  }
}

// const handleFileChange = (e) => {
//   const reader = new FileReader()
//   reader.readAsDataURL(e.raw)
//   reader.onload = () => {
//     file.value = reader.result
//   }
// }
// const onInterrupt = () => {
//   webuiStore.doInterrupt()
// }

onMounted(() => {
  webuiStore.loading = false
  // store.checkAndResetCredit()
})
</script>
