<template>
    <el-form-item label="Prompt:">
        <el-input v-model="webuiStore.inpaint.prompt" type="textarea" @keydown.stop @keyup.stop />
    </el-form-item>
    <el-form-item >
        <div style="display: flex;justify-content: space-between;width: 100%;">
            <el-button type="primary" :loading="webuiStore.loading" @click="onSubmit"
                style="width: 100%;overflow: hidden;">Generate</el-button>
            <!-- <el-button type="primary" :disabled="!webuiStore.loading" :loading="webuiStore.interrupt"
                @click="onInterrupt" style="width: 48%;">Interrupt</el-button> -->
        </div>
    </el-form-item>
</template>

<script name="App" setup>
import { useStore, useWebUIStore } from '@/stores'
// import { UploadFilled } from '@element-plus/icons-vue'
import { ElMessage } from 'element-plus'
import { reactive, onMounted, ref } from 'vue'
// import { getSelectArea, getActiveCanvas } from '@/utils/ps'

const webuiStore = useWebUIStore()
const store = useStore()

const onSubmit = async () => {
    if (webuiStore.inpaint.prompt === '') {
        ElMessage.error('Please enter a prompt')
        return
    }

    try {
        webuiStore.loading = true
        await webuiStore.inpaintHandle()
    } catch (err) {
        console.log('error', err)
        ElMessage.error(err.message)
    }
    webuiStore.loading = false
    console.log('submit!')
}

onMounted(() => {
})
</script>
