import { createApp } from 'vue'
// import { i18n } from '@/i18n'
import { bootstrap } from './ai/main'
import Banner from './banner/Index.vue'
import pinia from '@/stores'
import ElementPlus from 'element-plus'
import 'element-plus/dist/index.css'
import { useWebUIStore } from '@/stores'


let webuiStore = null
let lastLink = null

async function bootstrapBanner() {
    const app = createApp(Banner)
    app.use(pinia);
    app.use(ElementPlus)
    app.mount('#ap-banner')

}
bootstrapBanner();



function renderCanvas(src) {
    let activebV = window.ps._j3.avd
    let bV = window.ps._j3.dU[activebV]
    let activeLayer = bV.Y[0]
    let j4 = bV.U[activeLayer]
    let w = j4.w.r
    let h = j4.w.$
    // Create image element and load src
    let img = new Image();
    img.crossOrigin = "Anonymous"; // Enable CORS
    img.src = src;
    img.onload = () => {
        console.log('img Size:', src, img.width, img.height, 'j4 Size:', w, h)
        // Create temporary canvas with target dimensions
        let canvas = document.createElement('canvas');
        canvas.width = w;  // Use j4's width
        canvas.height = h; // Use j4's height
        let ctx = canvas.getContext('2d');

        // Draw image scaled to match target dimensions
        ctx.drawImage(img, 0, 0, w, h);

        // Get image data at the correct size
        let imageData = ctx.getImageData(0, 0, w, h);

        // Create new buffer with same size as j4.buffer
        let newBuffer = new Uint8Array(j4.buffer.length);

        // Copy data from imageData
        for (let i = 0; i < imageData.data.length; i++) {
            newBuffer[i] = imageData.data[i];
        }

        j4.buffer = newBuffer;

        console.log('Options page renderCanvas...');
        j4.rw();
        bV.rw();
    }
}


if (chrome.runtime) {
    chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
        console.log('Options page Received message from background:', request);
        if (request.type === 'new_image' && request.src !== lastLink) {
            renderCanvas(request.src);
            lastLink = request.src
        }
    });
}



document.addEventListener('loadPlugin', async (event) => {
    if (!webuiStore) {
        webuiStore = useWebUIStore(pinia)
    }
    let vcolumns = document.querySelectorAll('div.rightbar div.sbar.vcolumn')
    if (vcolumns.length == 2) {
        // 创建新元素
        let newColumn = document.createElement('div');
        newColumn.id = 'ap-web-ui'
        newColumn.style.borderLeft = 'solid 1px #252525'
        newColumn.style.height = '100%'
        newColumn.classList.add('sbar', 'vcolumn');
        vcolumns[1].parentNode.insertBefore(newColumn, vcolumns[1]);
        await bootstrap(newColumn)
    }
    webuiStore.clickIcon(event.detail.name)
    setTimeout(() => {
        window.ps._j3.jP()
    }, 200)
    return

});
