        <el-select v-model="style_preset" placeholder="Select" size="large" style="width: 100%">
            <el-option v-for="item in stylePresetOptions" :key="item.value" :label="item.label" :value="item.value" />
        </el-select>
    </el-form-item> -->
    <el-form-item>
        <div style="display: flex;justify-content: space-between;width: 100%;">
            <el-button type="primary" @click="onSubmit"
                style="width: 100%;overflow: hidden;">Generate</el-button>
