<script name="App" setup>
import { useStore, useWebUIStore } from '@/stores'
import { UploadFilled } from '@element-plus/icons-vue'
import { ElMessage } from 'element-plus'
import { reactive, onMounted, ref } from 'vue'
import { getSelectArea, getActiveCanvas } from '@/utils/ps'
const text = ref('');
const webuiStore = useWebUIStore()
const store = useStore()

const style_preset = ref('None')
const stylePresetOptions = [
    { value: "None", label: "None" },
    { value: "3d-model", label: "3D Model" },
    { value: "analog-film", label: "Analog Film" },
    { value: "anime", label: "Anime" },
    { value: "cinematic", label: "Cinematic" },
    { value: "comic-book", label: "Comic Book" },
    { value: "digital-art", label: "Digital Art" },
    { value: "enhance", label: "Enhance" },
    { value: "fantasy-art", label: "Fantasy Art" },
    { value: "isometric", label: "Isometric" },
    { value: "line-art", label: "Line Art" },
    { value: "low-poly", label: "Low Poly" },
    { value: "modeling-compound", label: "Modeling Compound" },
    { value: "neon-punk", label: "Neon Punk" },
    { value: "origami", label: "Origami" },
    { value: "photographic", label: "Photographic" },
    { value: "pixel-art", label: "Pixel Art" },
    { value: "tile-texture", label: "Tile Texture" }
];



const onSubmit = async () => {
    if (webuiStore.txt2img.prompt === '') {
        ElMessage.error('Please enter a prompt')
        return
    }

    try {
        webuiStore.loading = true
        await webuiStore.txt2imgHandle()
    } catch (err) {
        console.log('error', err)
        ElMessage.error(err.message)
    }
    webuiStore.loading = false
    console.log('submit!')
}

onMounted(() => {
    console.log("webuiStore.txt2img",webuiStore.txt2img)
})
</script>
