import { createApp } from 'vue'
// import { i18n } from '@/i18n'
import LocalApp from './LocalWebUI.vue'
import RemoteApp from './Remote.vue'
import pinia from '@/stores'
import ElementPlus from 'element-plus'
import 'element-plus/dist/index.css'



export async function bootstrapLocal(parentNode) {
    let container = document.createElement('div');
    document.body.appendChild
    container.id = 'ap-web-ui-local'
    parentNode.appendChild(container);

    const app = createApp(LocalApp)
    // app.use(i18n)
    app.use(pinia);
    app.use(ElementPlus)
    app.mount('#ap-web-ui-local')

}


export async function bootstrapRemote(parentNode) {
    let container = document.createElement('div');
    document.body.appendChild
    container.id = 'ap-web-ui-remote'
    parentNode.appendChild(container);

    const app = createApp(RemoteApp)
    // app.use(i18n)
    app.use(pinia);
    app.use(ElementPlus)
    app.mount('#ap-web-ui-remote')
}

export async function bootstrap(parentNode) {
    await bootstrapLocal(parentNode)
    await bootstrapRemote(parentNode)
}



